INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$NamecheapVPN$q$, $q$Consumer VPN service offered as part of Namecheap's privacy-focused product suite.$q$, 6);
