INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$Broad product suite spanning domains, hosting, email, SSL, and VPN$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$Strong reputation for customer support and internet-freedom advocacy$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$Wide selection of TLDs and bulk domain management tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$Renewal pricing on domains and hosting is notably higher than promotional first-year rates$q$, 0);
