INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$Who founded Namecheap?$q$, $q$Namecheap was founded in 2000 by Richard Kirkendall, who served as CEO until stepping down in December 2025.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$Where is Namecheap headquartered?$q$, $q$Namecheap is headquartered in Phoenix, Arizona.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$How much does a domain cost on Namecheap?$q$, $q$Pricing varies by TLD; popular domains like .com are often available from around 5.98 dollars in the first year promotionally, with higher standard renewal pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$Does Namecheap offer web hosting?$q$, $q$Yes, Namecheap offers Stellar shared hosting, EasyWP managed WordPress hosting, and VPS/dedicated server hosting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$Is domain privacy free on Namecheap?$q$, $q$Yes, Namecheap includes free WHOIS privacy protection with domain registrations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$Who owns Namecheap?$q$, $q$Namecheap was majority-acquired by private equity firm CVC Capital Partners in September 2025, valuing the company at about 1.5 billion dollars.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$Individual domain registration$q$, $q$Bloggers, freelancers, and individuals register domains with free privacy protection.$q$, $q$Individuals and freelancers$q$, 0);
