INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Namecheap is an ICANN-accredited domain registrar and web hosting company founded in 2000 by Richard Kirkendall and headquartered in Phoenix, Arizona. It has grown into one of the world's largest domain registrars, known for competitive pricing and a public focus on privacy and internet freedom.$q$, $q$In September 2025, private equity firm CVC Capital Partners acquired a majority stake in the company at a valuation of approximately 1.5 billion dollars, and Richard Kirkendall stepped down as CEO in December 2025, succeeded by longtime COO Hillan Klein.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Namecheap's core offering is domain registration across hundreds of TLDs, bundled with free WHOIS privacy protection, alongside SSL certificates, professional email, and a content delivery network.$q$, $q$Its hosting lineup includes Stellar shared hosting (Stellar, Stellar Plus, Stellar Business), EasyWP managed WordPress hosting, and VPS/dedicated server options, plus NamecheapVPN, a consumer VPN service.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4262ba7b-6a19-41ce-bc48-4ff58e432ce9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Domain pricing varies by TLD, with popular options like .com often available from around 5.98 dollars in the first year promotionally before renewing higher. Stellar shared hosting starts around 2.28 dollars per month on an introductory annual term (renewing near 3.88 dollars per month), while EasyWP managed WordPress hosting starts around 9.88 dollars per month at renewal.$q$]::text[], 2);
