-- ── MyCase ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$MyCase is cloud-based legal practice management software for law firms, covering case management, billing, trust accounting, and client communication.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$50/user/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$About 195-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Diego, California (part of 8am / AffiniPay, headquartered in Austin, Texas)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$MyCase Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MyCase review 2026: legal practice management pricing, case and billing features, trust accounting, and how it compares to Clio and other law firm software.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$MyCase is a cloud-based legal practice management platform founded in 2010 in San Diego, California, by Matt Spiegel, a former criminal defense attorney, along with co-founders Alex Dikowski and Chris Schulte. Spiegel started the company after struggling to track cases and client communications in his own solo practice, aiming to build software that would help law firms avoid missed deadlines and communication failures. MyCase grew to serve more than 500,000 users and was acquired by property-management software company AppFolio in October 2012, giving it access to greater engineering resources under AppFolio's Santa Barbara-headquartered operation. In September 2020, AppFolio sold MyCase to funds advised by private equity firm Apax Partners for approximately 193 million dollars, spinning it out as an independent legal-tech company again. In June 2022, MyCase was acquired by AffiniPay, the parent company of LawPay, which has since rebranded its combined legal and accounting software portfolio (including MyCase, LawPay, CASEpeer, and Woodpecker) under the unified '8am' brand. As of 2026 MyCase (as part of 8am) has roughly 195 to 200 employees. The product itself is an all-in-one practice management suite covering case and contact management, calendaring, document storage and generation, time tracking, invoicing, online client payments, and trust (IOLTA) accounting, along with a secure client portal for two-way communication. MyCase is sold on a per-user, per-month subscription across three tiers: Basic (listed around 50 dollars per user per month billed annually, or 60 dollars month-to-month) covering core case management, billing, trust accounting, and a limited client portal; Pro (around 100 dollars per user per month annually, or 120 dollars monthly), the most popular tier, which adds unlimited eSignature, document automation, automated workflows, client intake forms, two-way texting, an AI writing assistant branded '8am IQ', and 70-plus third-party integrations; and Advanced (around 130 dollars per user per month annually, or 150 dollars monthly), which layers on an AI case assistant, OCR-based discovery assistance, advanced document automation, conflict-check tracking, split billing, and open API access. A separate MyCase Accounting add-on and LawPay-powered online payment processing (with no extra monthly fee) are also available. MyCase's target audience is small and mid-sized law firms, particularly solo and boutique practices in areas like personal injury, family law, and criminal defense, who need an affordable, unified system rather than stitching together separate billing, document, and communication tools. Its main competitors in the legal practice management category include Clio, PracticePanther, Smokeball, CosmoLex, and Filevine, with MyCase generally positioned as a strong value option for smaller firms due to its bundled billing, trust accounting, and client communication features at a moderate per-user price point.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b4459135-cfd3-4027-bdc1-046357985283';

