-- ── MySQL ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$MySQL is a widely used open-source relational database management system, now owned by Oracle, offered as a free Community Edition and paid Enterprise editions.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); Enterprise from $5,350/server/year$q$, starting_price),
  founded_year = COALESCE(1995, founded_year),
  company_size = COALESCE($q$Owned by Oracle Corporation (160,000+ employees)$q$, company_size),
  headquarters = COALESCE($q$Austin, Texas, US (Oracle Corporation); originally founded in Uppsala, Sweden$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$MySQL Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MySQL review 2026: open-source database features, Community vs Enterprise pricing, architecture, and how it compares to PostgreSQL and MariaDB.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$MySQL is an open-source relational database management system originally created in 1995 in Sweden by Michael Widenius, David Axmark, and Allan Larsson, who founded the company MySQL AB to develop and commercialize it. Widenius had previously worked on an earlier database tool called UNIREG, and MySQL's core storage engine drew on that lineage. The database quickly became one of the core components of the 'LAMP' stack (Linux, Apache, MySQL, PHP/Perl/Python) that powered much of the early dynamic web, and its dual-licensing model, offering a free GPL-licensed Community Edition alongside paid commercial licenses, became a template for many later open-source companies. In January 2008, Sun Microsystems announced it would acquire MySQL AB for approximately 1 billion dollars. Sun itself was then acquired by Oracle Corporation in a deal valued at roughly 7.4 billion dollars, completed in 2010, bringing MySQL under Oracle's ownership, where it remains today, developed by the MySQL team within Oracle and headquartered with Oracle's operations (Oracle is based in Austin, Texas). Because of concerns about Oracle's stewardship, several of MySQL's original developers, including Michael Widenius, forked the codebase in 2009 to create MariaDB as a community-driven, drop-in-compatible alternative. Architecturally, MySQL is a client-server relational database supporting multiple storage engines (most notably InnoDB, its default transactional engine), ACID-compliant transactions, replication, partitioning, and a standard SQL interface, and it runs on Linux, Windows, and macOS. Oracle distributes MySQL in several editions: the free, open-source MySQL Community Edition under the GPL, which has no artificial restrictions on data volume, connections, or core features; MySQL Standard Edition, a paid commercial edition priced by server socket count with tiers roughly between 2,140 and 12,840 dollars per year depending on socket count and support level, bundling Oracle Premier Support; MySQL Enterprise Edition, priced roughly between 5,350 and 32,100 dollars per year per server depending on socket count, which adds enterprise features such as MySQL Enterprise Monitor, Enterprise Backup, Enterprise Security, Enterprise Audit, and Enterprise High Availability tooling on top of Premier Support; and MySQL Cluster Carrier Grade Edition (CGE), the highest tier, priced from roughly 10,700 to 64,200 dollars per year per server, intended for carrier-grade, high-availability clustered deployments. MySQL's target audience spans nearly the entire spectrum of software development: solo developers and startups running the free Community Edition for websites and applications, through to large enterprises paying for Enterprise or Cluster CGE editions for mission-critical, high-availability workloads with vendor support and advanced tooling. It also underpins Oracle's fully managed MySQL HeatWave cloud database service. MySQL's principal competitors include PostgreSQL, MariaDB (its own community fork), Microsoft SQL Server, and various NoSQL and cloud-native databases, with MySQL differentiated by its enormous installed base, deep integration into the historical LAMP/web-hosting ecosystem, and broad compatibility with hosting providers, CMS platforms (like WordPress), and application frameworks worldwide.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '76f0c5ad-2a6b-4da7-9d21-98785efc0c74';

