-- ── n8n ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$n8n is a source-available workflow automation and AI agent platform that combines a visual node-based editor with the flexibility of custom code.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); Cloud from EUR20/month billed annually$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Approximately 1,000 employees$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$n8n Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$n8n review 2026: workflow automation and AI agent platform pricing, features, self-hosting options, and how it compares to Zapier and Make.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$n8n is a workflow automation and AI agent platform built by n8n GmbH, a company founded by Jan Oberhauser in Berlin, Germany, with the software first released publicly in 2019 (the name is often described as shorthand for 'nodemation'). n8n combines a visual, node-based workflow editor with the ability to drop into JavaScript or Python code within any node, positioning it as a tool that gives technical teams both the speed of no-code automation and the flexibility of custom code, distinguishing it from purely no-code competitors like Zapier and Make. The software is source-available (fair-code licensed) rather than fully open source in the OSI sense, and it offers a free, self-hostable Community Edition that developers can run on their own infrastructure with unlimited workflow executions, in addition to a paid n8n Cloud hosted service. n8n has raised substantial venture funding: a 1.5 million dollar seed round in March 2020 co-led by Sequoia Capital and firstminute capital, a 12 million dollar Series A in April 2021 led by Felicis Ventures, a roughly 55 million euro (about 60 million dollar) Series B in March 2025 led by Highland Europe, and a 180 million dollar Series C in October 2025 that valued the company at 2.5 billion dollars; by mid-2026 reports place the company's valuation at approximately 5.2 billion dollars with roughly 1,000 employees. n8n's product architecture centers on workflows made of connected 'nodes,' each representing a trigger, action, or logic step (HTTP requests, database operations, app integrations, conditionals, loops, and AI/LLM steps), with native support for building AI agents that call language models and tools as part of a workflow, reflecting the platform's pivot toward AI-driven automation alongside traditional business-process automation. n8n Cloud pricing is usage-based on workflow executions rather than per-step pricing: the Starter plan is priced at 20 euros per month billed annually for 2,500 executions per month with unlimited steps and 5 concurrent executions; the Pro plan is 50 euros per month billed annually for 10,000 executions per month, 20 concurrent executions, and added features like admin roles and workflow history; the Business plan is priced around 667 euros per month billed annually for 40,000 executions, 30 concurrent executions, SSO/SAML/LDAP, and self-hosted deployment options; and an Enterprise plan offers custom volume, 200-plus concurrent executions, unlimited projects, external secret store integration, log streaming, and dedicated support with an SLA. A Startup Program offers discounted pricing (reported around 400 dollars per month) with unlimited executions and enterprise features for early-stage companies meeting funding and headcount criteria. n8n's target audience includes technical teams, developers, IT and operations staff, and increasingly AI/automation engineers who want to build complex multi-step automations and AI agents without being limited to the constrained logic of simpler no-code tools. Its main competitors include Zapier, Make (formerly Integromat), Microsoft Power Automate, and Workato, with n8n differentiated primarily by its self-hosting option, per-execution (not per-step) pricing model, and deep support for custom code and AI agent building within workflows.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2345d0ed-4255-4773-9565-b0ced4967bcd';

