-- ── Nagios ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Nagios (Nagios Core) is a free, open-source IT infrastructure monitoring engine that checks hosts, services, and networks and issues alerts when problems occur.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1999, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Saint Paul, Minnesota, US (Nagios Enterprises)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Nagios Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Nagios Core review 2026: free open-source IT monitoring engine features, plugin architecture, alerting, and how it compares to Zabbix and Nagios XI.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Nagios is a free, open-source IT infrastructure monitoring engine originally written by Ethan Galstad, who released the first version, called NetSaint, on March 14, 1999. In 2002, after the owners of a similarly named trademark raised a legal objection, Galstad renamed the project to Nagios, a recursive backronym for 'Nagios Ain't Gonna Insist On Sainthood.' The core monitoring engine, now called Nagios Core, remains free and open source under the GNU General Public License version 2 (GPL v2), meaning anyone can download, run, and modify it without cost. In 2007, Galstad founded a company called Nagios Enterprises, headquartered at 1295 Bandana Boulevard North, Saint Paul, Minnesota, to provide commercial products, training, and paid support built around the open-source core; the company's commercial flagship product is Nagios XI, a separate paid product distinct from the free Nagios Core engine. Nagios Core's architecture consists of three main components: a scheduler/processing core that runs checks according to a defined schedule, a plugin system that performs the actual host and service checks (over 3,000 community-contributed plugins exist, plus roughly 50 official plugins maintained by the Nagios team), and a web-based GUI for viewing monitoring status, alerts, and historical data. Nagios uses both agent-based and agentless monitoring approaches; agentless monitoring commonly relies on protocols like SNMP to gather data from remote devices without installing extra software, while agent-based approaches (for example using NRPE or NSCA) allow deeper checks on remote hosts. Core capabilities include configurable alert thresholds for various performance metrics, notifications via email, SMS, or other channels when thresholds are breached or hosts/services go down, and APIs that make it straightforward to integrate Nagios Core with third-party or custom-built applications and dashboards. Because Nagios Core is entirely free with no tiered pricing, there is no formal 'company size' or revenue tied to Core itself; the surrounding commercial entity, Nagios Enterprises, is a privately held company that also develops and sells Nagios XI, Nagios Log Server, Nagios Fusion, and Nagios Network Analyzer as paid products layered on top of or alongside the free Core engine. Nagios Core's target audience is systems administrators, DevOps engineers, and IT operations teams, particularly those who want full control over a self-hosted, highly extensible, no-cost monitoring engine and are comfortable configuring it via configuration files or the community-built plugin ecosystem, as opposed to teams wanting a polished, GUI-driven commercial product (which would point them toward Nagios XI instead). Its primary open-source and commercial competitors include Zabbix, Icinga (itself originally a fork of Nagios), Prometheus with Grafana, Checkmk, PRTG, and Datadog, with Nagios Core differentiated by its long history (over two decades in production use), enormous plugin ecosystem, and reputation as one of the original and most battle-tested open-source monitoring tools in enterprise IT.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6fe712b1-9844-4be1-8956-48e550068b64';

